"use client";

import * as React from "react";
import {
  LocaleProvider,
  ToastProvider,
  useToast,
  Container,
  PageHeader,
  Card,
  CardHeader,
  CardTitle,
  CardDescription,
  CardContent,
  VStack,
  HStack,
  Cluster,
  Grid,
  Separator,
  StatGroup,
  Tabs,
  TabsList,
  TabsTrigger,
  TabsContent,
  SearchInput,
  FilterChips,
  SegmentedControl,
  Combobox,
  DateRangePicker,
  Button,
  Badge,
  Icon,
  Img,
  ImagePreview,
  MetadataList,
  EmptyState,
  Skeleton,
  AssetGrid,
  AssetInspectorPanel,
  MediaLibraryTemplate,
  MediaPickerDialog,
  FileUploader,
  Dialog,
  DialogContent,
  DialogHeader,
  DialogTitle,
  DialogDescription,
  DialogFooter,
  type AssetCardAsset,
  type MetadataListItem,
  type FilterChip,
} from "@gunjo/ui";
import type { DateRange } from "react-day-picker";
import {
  IconCamera,
  IconUpload,
  IconFolderPlus,
  IconChevronLeft,
  IconChevronRight,
  IconMapPin,
  IconStack2,
  IconRuler2,
  IconCalendarEvent,
  IconClipboardCheck,
  IconAlertTriangle,
  IconStar,
} from "@tabler/icons-react";

/* ------------------------------------------------------------------ */
/* ドメインモデル                                                      */
/* ------------------------------------------------------------------ */

type Koushu = "掘削" | "配筋" | "型枠" | "コンクリート" | "設備";
type Koutei = "着手前" | "施工中" | "完了" | "検査";

/** 施工写真1枚。AssetCardAsset を拡張し、黒板（工事名/工種/測点…）情報をひもづける。 */
interface Photo extends AssetCardAsset {
  koushu: Koushu;
  koutei: Koutei;
  /** 撮影場所（階・部屋・方位） */
  place: string;
  floor: string;
  /** 測点 */
  station: string;
  /** 工事名（黒板1行目） */
  work: string;
  comment: string;
}

const KOUSHU_LIST: Koushu[] = ["掘削", "配筋", "型枠", "コンクリート", "設備"];
const KOUTEI_LIST: Koutei[] = ["着手前", "施工中", "完了", "検査"];
const WORK_NAME = "第二期 A棟新築工事";

function img(seed: string): string {
  return `https://picsum.photos/seed/${seed}/900/675`;
}

const PHOTOS: Photo[] = [
  {
    id: "p-001",
    title: "根切り底 掘削状況",
    src: img("koutei-kutsu-1"),
    alt: "地下1階の根切り底の掘削状況",
    koushu: "掘削",
    koutei: "施工中",
    place: "地下1階 北側",
    floor: "B1F",
    station: "X3-Y2",
    work: WORK_NAME,
    comment: "床付け前。湧水なし。深さ GL-4,200。",
    createdAt: "2026-07-14",
    rating: 4,
  },
  {
    id: "p-002",
    title: "床付け完了",
    src: img("kutsu-2"),
    alt: "掘削の床付け完了状況",
    koushu: "掘削",
    koutei: "完了",
    place: "地下1階 北側",
    floor: "B1F",
    station: "X3-Y2",
    work: WORK_NAME,
    comment: "監督確認済み。砕石転圧後。",
    createdAt: "2026-07-14",
    isFavorite: true,
  },
  {
    id: "p-010",
    title: "基礎配筋 D19@200",
    src: img("haikin-1"),
    alt: "基礎の配筋状況",
    koushu: "配筋",
    koutei: "検査",
    place: "1階 基礎梁 通り芯 X2",
    floor: "1F",
    station: "X2-Y1",
    work: WORK_NAME,
    comment: "主筋 D19@200、あばら筋 D13@150。かぶり 60mm 確認。",
    createdAt: "2026-07-15",
    rating: 5,
  },
  {
    id: "p-011",
    title: "スラブ上端筋 結束",
    src: img("haikin-2"),
    alt: "スラブ上端筋の結束状況",
    koushu: "配筋",
    koutei: "施工中",
    place: "2階 スラブ 東",
    floor: "2F",
    station: "X4-Y3",
    work: WORK_NAME,
    comment: "結束線ピッチ確認。開口補強筋未施工。",
    createdAt: "2026-07-16",
  },
  {
    id: "p-020",
    title: "柱型枠 建込み",
    src: img("katawaku-1"),
    alt: "柱型枠の建込み状況",
    koushu: "型枠",
    koutei: "施工中",
    place: "1階 C2柱 南面",
    floor: "1F",
    station: "X2-Y3",
    work: WORK_NAME,
    comment: "セパ間隔 600。垂直確認済み。",
    createdAt: "2026-07-16",
  },
  {
    id: "p-021",
    title: "壁型枠 完了",
    src: img("katawaku-2"),
    alt: "壁型枠の完了状況",
    koushu: "型枠",
    koutei: "完了",
    place: "1階 EV シャフト",
    floor: "1F",
    station: "X1-Y2",
    work: WORK_NAME,
    comment: "はらみ止め設置済み。清掃口確認。",
    createdAt: "2026-07-16",
    rating: 3,
  },
  {
    id: "p-030",
    title: "1階スラブ 打設状況",
    src: img("concrete-1"),
    alt: "1階スラブのコンクリート打設状況",
    koushu: "コンクリート",
    koutei: "施工中",
    place: "1階 スラブ 全面",
    floor: "1F",
    station: "X3-Y3",
    work: WORK_NAME,
    comment: "呼び強度 24-18-20N。バイブレータ2台。",
    createdAt: "2026-07-17",
  },
  {
    id: "p-031",
    title: "テストピース採取",
    src: img("concrete-2"),
    alt: "コンクリートのテストピース採取状況",
    koushu: "コンクリート",
    koutei: "検査",
    place: "1階 荷取りヤード",
    floor: "1F",
    station: "-",
    work: WORK_NAME,
    comment: "スランプ 18.0cm、空気量 4.5%。供試体6本。",
    createdAt: "2026-07-17",
    isFavorite: true,
    rating: 4,
  },
];

/* ------------------------------------------------------------------ */
/* ユーティリティ                                                      */
/* ------------------------------------------------------------------ */

const KOUTEI_TONE: Record<Koutei, "secondary" | "info" | "success" | "warning"> = {
  着手前: "secondary",
  施工中: "info",
  完了: "success",
  検査: "warning",
};

function photoMetadata(p: Photo): MetadataListItem[] {
  return [
    { label: "工事名", value: p.work, icon: <Icon icon={IconClipboardCheck} size="sm" decorative />, wrap: true },
    { label: "工種", value: p.koushu, icon: <Icon icon={IconStack2} size="sm" decorative /> },
    { label: "工程", value: <Badge variant={KOUTEI_TONE[p.koutei]}>{p.koutei}</Badge> },
    { label: "測点", value: p.station, icon: <Icon icon={IconRuler2} size="sm" decorative /> },
    { label: "撮影場所", value: p.place, icon: <Icon icon={IconMapPin} size="sm" decorative />, wrap: true },
    { label: "撮影日", value: p.createdAt ?? "-", icon: <Icon icon={IconCalendarEvent} size="sm" decorative /> },
  ];
}

/** グリッド内サムネイル下のメタ（工種・工程・場所）。 */
function renderPhotoMeta(p: Photo): React.ReactNode {
  return (
    <VStack gap={1} className="mt-1">
      <Cluster gap={1}>
        <Badge variant="outline" size="sm">
          {p.koushu}
        </Badge>
        <Badge variant={KOUTEI_TONE[p.koutei]} size="sm">
          {p.koutei}
        </Badge>
      </Cluster>
      <HStack gap={1} align="center" className="text-xs text-muted-foreground">
        <Icon icon={IconMapPin} size="xs" decorative />
        <span className="truncate">{p.place}</span>
      </HStack>
    </VStack>
  );
}

/* ------------------------------------------------------------------ */
/* 是正記録（before / after）                                          */
/* ------------------------------------------------------------------ */

interface FixPair {
  id: string;
  issue: string;
  koushu: Koushu;
  place: string;
  resolved: boolean;
  before: { src: string; alt: string; date: string; note: string };
  after: { src: string; alt: string; date: string; note: string } | null;
}

const FIX_PAIRS: FixPair[] = [
  {
    id: "fix-1",
    issue: "あばら筋の間隔が図面値を超過（@200 → @150 へ是正）",
    koushu: "配筋",
    place: "1F 基礎梁 X2 通り",
    resolved: true,
    before: { src: img("fix-1-before"), alt: "是正前のあばら筋間隔", date: "2026-07-15", note: "@200 で配筋。指摘。" },
    after: { src: img("fix-1-after"), alt: "是正後のあばら筋間隔", date: "2026-07-15", note: "@150 に是正、再検査合格。" },
  },
  {
    id: "fix-2",
    issue: "型枠セパレータの端部かぶり不足",
    koushu: "型枠",
    place: "1F C2柱 南面",
    resolved: true,
    before: { src: img("fix-2-before"), alt: "是正前のセパかぶり", date: "2026-07-16", note: "端部かぶり 20mm。指摘。" },
    after: { src: img("fix-2-after"), alt: "是正後のセパかぶり", date: "2026-07-16", note: "スペーサ追加、40mm 確保。" },
  },
  {
    id: "fix-3",
    issue: "打継ぎ面のレイタンス処理未実施",
    koushu: "コンクリート",
    place: "1F スラブ 打継ぎ部",
    resolved: false,
    before: { src: img("fix-3-before"), alt: "是正前の打継ぎ面", date: "2026-07-17", note: "レイタンス残存。是正指示中。" },
    after: null,
  },
];

/* ================================================================== */
/* 画面本体                                                            */
/* ================================================================== */

function Screen() {
  const { showToast } = useToast();

  // ------- フィルタ状態 -------
  const [query, setQuery] = React.useState("");
  const [koushu, setKoushu] = React.useState<string>("all");
  const [koutei, setKoutei] = React.useState<string>("all");
  const [floor, setFloor] = React.useState<string>("");
  const [range, setRange] = React.useState<DateRange | undefined>(undefined);

  // ------- 選択・表示状態 -------
  const [photos, setPhotos] = React.useState<Photo[]>(PHOTOS);
  const [selectedIds, setSelectedIds] = React.useState<Set<string>>(new Set());
  const [activeId, setActiveId] = React.useState<string | null>("p-010");
  const [previewId, setPreviewId] = React.useState<string | null>(null);
  const [reportIds, setReportIds] = React.useState<string[]>([]);

  // ------- ダイアログ -------
  const [uploadOpen, setUploadOpen] = React.useState(false);
  const [pickerOpen, setPickerOpen] = React.useState(false);
  const [uploadFiles, setUploadFiles] = React.useState<File[]>([]);

  // ------- 読み込み演出 -------
  const [isLoading, setIsLoading] = React.useState(true);
  React.useEffect(() => {
    const t = setTimeout(() => setIsLoading(false), 650);
    return () => clearTimeout(t);
  }, []);

  // ------- 絞り込み -------
  const filtered = React.useMemo(() => {
    const from = range?.from ? new Date(range.from.setHours(0, 0, 0, 0)) : null;
    const to = range?.to ? new Date(range.to.setHours(23, 59, 59, 999)) : null;
    return photos.filter((p) => {
      if (koushu !== "all" && p.koushu !== koushu) return false;
      if (koutei !== "all" && p.koutei !== koutei) return false;
      if (floor && p.floor !== floor) return false;
      if (query) {
        const hay = `${p.title} ${p.place} ${p.station} ${p.comment}`.toLowerCase();
        if (!hay.includes(query.toLowerCase())) return false;
      }
      if ((from || to) && p.createdAt) {
        const d = new Date(p.createdAt);
        if (from && d < from) return false;
        if (to && d > to) return false;
      }
      return true;
    });
  }, [photos, koushu, koutei, floor, query, range]);

  const activePhoto = React.useMemo(
    () => photos.find((p) => p.id === activeId) ?? null,
    [photos, activeId],
  );

  const previewIndex = filtered.findIndex((p) => p.id === previewId);
  const previewPhoto = previewIndex >= 0 ? filtered[previewIndex] : null;

  // ------- ハンドラ -------
  const toggleSelect = React.useCallback((asset: AssetCardAsset) => {
    setActiveId(asset.id);
    setSelectedIds((prev) => {
      const next = new Set(prev);
      if (next.has(asset.id)) next.delete(asset.id);
      else next.add(asset.id);
      return next;
    });
  }, []);

  const openPreview = React.useCallback((asset: AssetCardAsset) => {
    setActiveId(asset.id);
    setPreviewId(asset.id);
  }, []);

  const toggleFavorite = React.useCallback(
    (asset: AssetCardAsset) => {
      setPhotos((prev) =>
        prev.map((p) => (p.id === asset.id ? { ...p, isFavorite: !p.isFavorite } : p)),
      );
    },
    [],
  );

  const updateNote = React.useCallback((note: string) => {
    setActiveId((id) => {
      if (id) setPhotos((prev) => prev.map((p) => (p.id === id ? { ...p, comment: note } : p)));
      return id;
    });
  }, []);

  const clearFilters = () => {
    setQuery("");
    setKoushu("all");
    setKoutei("all");
    setFloor("");
    setRange(undefined);
  };

  const hasActiveFilter = query !== "" || koushu !== "all" || koutei !== "all" || floor !== "" || !!range;

  // ------- 派生データ -------
  const koushuChips: FilterChip[] = React.useMemo(
    () => [
      { value: "all", label: "すべて", count: photos.length },
      ...KOUSHU_LIST.map((k) => ({
        value: k,
        label: k,
        count: photos.filter((p) => p.koushu === k).length,
      })),
    ],
    [photos],
  );

  const floorOptions = React.useMemo(() => {
    const set = Array.from(new Set(photos.map((p) => p.floor))).sort();
    return set.map((f) => ({ value: f, label: `${f} 階層` }));
  }, [photos]);

  const todayCount = photos.filter((p) => p.createdAt === "2026-07-17").length;
  const needFixCount = FIX_PAIRS.filter((f) => !f.resolved).length;

  const stats = [
    { label: "総枚数", value: String(photos.length), hint: `絞り込み ${filtered.length} 枚` },
    { label: "本日の撮影", value: String(todayCount), hint: "7/17" },
    { label: "要是正", value: String(needFixCount), hint: `是正済 ${FIX_PAIRS.length - needFixCount}` },
    { label: "台帳 選択中", value: String(selectedIds.size), hint: `確定 ${reportIds.length} 枚` },
  ];

  /* ---------------- グリッド本体（読み込み / 空 / 一覧） ---------------- */
  let gridBody: React.ReactNode;
  if (isLoading) {
    gridBody = (
      <Grid minItemWidth={150} gap={3} aria-hidden>
        {Array.from({ length: 6 }).map((_, i) => (
          <VStack key={i} gap={2}>
            <Skeleton shape="rectangle" className="aspect-[4/3] w-full rounded-md" />
            <Skeleton shape="text" className="h-3 w-2/3" />
            <Skeleton shape="text" className="h-3 w-1/2" />
          </VStack>
        ))}
      </Grid>
    );
  } else if (filtered.length === 0) {
    gridBody = (
      <EmptyState
        icon={<Icon icon={IconCamera} size="xl" decorative />}
        title={koushu !== "all" ? `「${koushu}」の写真はまだありません` : "条件に合う写真がありません"}
        description={
          koushu !== "all"
            ? "この工種の撮影がまだ登録されていません。現場で撮影した写真を取り込みましょう。"
            : "絞り込み条件を変えるか、写真を取り込んでください。"
        }
        headingLevel={3}
        action={
          <HStack gap={2}>
            <Button variant="outline" onClick={clearFilters}>
              条件をクリア
            </Button>
            <Button onClick={() => setUploadOpen(true)}>
              <Icon icon={IconUpload} size="sm" decorative /> 写真を取り込む
            </Button>
          </HStack>
        }
      />
    );
  } else {
    gridBody = (
      <AssetGrid
        items={filtered}
        selectedIds={selectedIds}
        selectionMode="multiple"
        minColumnWidth={150}
        gap={12}
        onSelect={toggleSelect}
        onPreview={openPreview}
        onFavorite={toggleFavorite}
        renderMeta={(p) => renderPhotoMeta(p as Photo)}
        aria-label="施工写真の一覧"
      />
    );
  }

  /* ---------------- デスクトップ用インスペクタ ---------------- */
  const inspector = (
    <AssetInspectorPanel
      asset={activePhoto}
      title={activePhoto?.title}
      note={activePhoto?.comment}
      tags={activePhoto ? [activePhoto.koushu, activePhoto.koutei, activePhoto.floor] : []}
      metadata={activePhoto ? photoMetadata(activePhoto) : []}
      onNoteChange={updateNote}
      onFavorite={toggleFavorite}
      onPreview={(a) => setPreviewId(a.id)}
      labels={{
        emptyTitle: "写真を選ぶと黒板情報が表示されます",
        title: "写真名",
        note: "コメント（黒板）",
        tags: "分類",
        metadata: "黒板情報",
        preview: "拡大表示",
        favorite: "重要マーク",
        edit: "編集",
        save: "保存",
        cancel: "取消",
        close: "閉じる",
      }}
    />
  );

  return (
    <div className="min-h-screen bg-background text-foreground">
      <PageHeader
        title="施工写真台帳"
        subtitle={`${WORK_NAME} ・ 現場監督: 大山`}
        sticky
        actions={
          <HStack gap={2} align="center">
            <Button variant="outline" size="sm" onClick={() => setUploadOpen(true)}>
              <Icon icon={IconUpload} size="sm" decorative /> <span className="hidden sm:inline">取り込み</span>
            </Button>
            <Button
              size="sm"
              onClick={() => {
                setSelectedIds(new Set(reportIds));
                setPickerOpen(true);
              }}
            >
              <Icon icon={IconFolderPlus} size="sm" decorative /> <span className="hidden sm:inline">台帳を作成</span>
            </Button>
          </HStack>
        }
      />

      <Container size="2xl" className="py-4">
        <VStack gap={4}>
          <StatGroup items={stats} cols={{ base: 2, md: 4 }} />

          <Tabs defaultValue="ledger">
            <TabsList>
              <TabsTrigger value="ledger">
                <Icon icon={IconCamera} size="sm" decorative /> 写真台帳
              </TabsTrigger>
              <TabsTrigger value="fix">
                <Icon icon={IconAlertTriangle} size="sm" decorative /> 是正記録
              </TabsTrigger>
            </TabsList>

            {/* ---------------- 写真台帳タブ ---------------- */}
            <TabsContent value="ledger">
              <VStack gap={4} className="pt-3">
                {/* 絞り込み */}
                <Card>
                  <CardHeader>
                    <CardTitle as="h2">絞り込み</CardTitle>
                    <CardDescription>工種・工程・撮影場所・日付・キーワードで写真を絞り込めます。</CardDescription>
                  </CardHeader>
                  <CardContent>
                    <VStack gap={3}>
                      <SearchInput
                        value={query}
                        onValueChange={setQuery}
                        placeholder="写真名・測点・コメントを検索"
                        aria-label="写真を検索"
                      />

                      <VStack gap={1}>
                        <span className="text-xs font-medium text-muted-foreground">工種</span>
                        <FilterChips
                          items={koushuChips}
                          value={koushu}
                          onValueChange={setKoushu}
                          aria-label="工種で絞り込み"
                        />
                      </VStack>

                      <VStack gap={1}>
                        <span className="text-xs font-medium text-muted-foreground">工程</span>
                        <SegmentedControl
                          aria-label="工程で絞り込み"
                          size="lg"
                          value={koutei}
                          onValueChange={setKoutei}
                          options={[
                            { value: "all", label: "すべて" },
                            ...KOUTEI_LIST.map((k) => ({ value: k, label: k })),
                          ]}
                        />
                      </VStack>

                      <Grid cols={{ base: 1, md: 2 }} gap={3}>
                        <Combobox
                          options={[{ value: "", label: "すべての階" }, ...floorOptions]}
                          value={floor}
                          onValueChange={setFloor}
                          placeholder="撮影場所（階）"
                          searchPlaceholder="階を検索"
                          aria-label="撮影場所で絞り込み"
                          clearable
                        />
                        <DateRangePicker
                          value={range}
                          onValueChange={setRange}
                          label={undefined}
                          placeholder="撮影日の範囲"
                          aria-label="撮影日で絞り込み"
                        />
                      </Grid>

                      {hasActiveFilter && (
                        <HStack justify="between" align="center" wrap>
                          <span className="text-sm text-muted-foreground">{filtered.length} 枚が該当</span>
                          <Button variant="ghost" size="sm" onClick={clearFilters}>
                            条件をクリア
                          </Button>
                        </HStack>
                      )}
                    </VStack>
                  </CardContent>
                </Card>

                {/* 選択中アクション */}
                {selectedIds.size > 0 && (
                  <Card>
                    <CardContent className="py-3">
                      <HStack justify="between" align="center" wrap gap={2}>
                        <span className="text-sm font-medium">{selectedIds.size} 枚を選択中</span>
                        <HStack gap={2}>
                          <Button variant="ghost" size="sm" onClick={() => setSelectedIds(new Set())}>
                            選択解除
                          </Button>
                          <Button
                            size="sm"
                            onClick={() => {
                              setReportIds(Array.from(selectedIds));
                              showToast(`${selectedIds.size} 枚を工事写真台帳に追加しました`, "success");
                            }}
                          >
                            <Icon icon={IconFolderPlus} size="sm" decorative /> 台帳に追加
                          </Button>
                        </HStack>
                      </HStack>
                    </CardContent>
                  </Card>
                )}

                {/* グリッド + インスペクタ（デスクトップは MediaLibraryTemplate の details に配置） */}
                <MediaLibraryTemplate details={inspector}>{gridBody}</MediaLibraryTemplate>
              </VStack>
            </TabsContent>

            {/* ---------------- 是正記録タブ ---------------- */}
            <TabsContent value="fix">
              <VStack gap={4} className="pt-3">
                <p className="text-sm text-muted-foreground">
                  検査での指摘と是正を、施工前（是正前）と施工後（是正後）の写真の対で記録します。
                </p>
                {FIX_PAIRS.map((f) => (
                  <Card key={f.id}>
                    <CardHeader>
                      <HStack justify="between" align="start" gap={2} wrap>
                        <VStack gap={1}>
                          <CardTitle as="h3">{f.issue}</CardTitle>
                          <CardDescription>
                            {f.koushu} ・ {f.place}
                          </CardDescription>
                        </VStack>
                        {f.resolved ? (
                          <Badge variant="success" icon={<Icon icon={IconClipboardCheck} size="sm" decorative />}>
                            是正済
                          </Badge>
                        ) : (
                          <Badge variant="warning" icon={<Icon icon={IconAlertTriangle} size="sm" decorative />}>
                            是正中
                          </Badge>
                        )}
                      </HStack>
                    </CardHeader>
                    <CardContent>
                      <Grid cols={2} gap={3}>
                        <BeforeAfterCell label="是正前" tone="warning" data={f.before} />
                        {f.after ? (
                          <BeforeAfterCell label="是正後" tone="success" data={f.after} />
                        ) : (
                          <VStack gap={2}>
                            <Badge variant="secondary">是正後</Badge>
                            <div className="flex aspect-[4/3] w-full items-center justify-center rounded-md border border-dashed text-center text-xs text-muted-foreground">
                              是正写真 未登録
                            </div>
                          </VStack>
                        )}
                      </Grid>
                    </CardContent>
                  </Card>
                ))}
              </VStack>
            </TabsContent>
          </Tabs>
        </VStack>
      </Container>

      {/* ============ 拡大表示ダイアログ（自前ライトボックス） ============ */}
      <Dialog open={previewId !== null} onOpenChange={(o) => !o && setPreviewId(null)}>
        <DialogContent className="max-w-4xl" closeLabel="閉じる">
          {previewPhoto && (
            <>
              <DialogHeader>
                <DialogTitle>{previewPhoto.title}</DialogTitle>
                <DialogDescription>
                  {previewIndex + 1} / {filtered.length} 枚
                </DialogDescription>
              </DialogHeader>

              <div className="grid gap-4 md:grid-cols-[minmax(0,1.6fr)_minmax(0,1fr)]">
                {/* 拡大画像 + 前後移動 */}
                <div className="relative">
                  <Img
                    src={previewPhoto.src}
                    alt={previewPhoto.alt ?? previewPhoto.title}
                    aspectRatio="video"
                    objectFit="contain"
                    showSkeleton
                    className="w-full rounded-md bg-muted"
                  />
                  <HStack justify="between" align="center" className="mt-2">
                    <Button
                      variant="outline"
                      size="sm"
                      disabled={previewIndex <= 0}
                      onClick={() => setPreviewId(filtered[previewIndex - 1]?.id ?? null)}
                      aria-label="前の写真"
                    >
                      <Icon icon={IconChevronLeft} size="sm" decorative /> 前へ
                    </Button>
                    <Button
                      variant={previewPhoto.isFavorite ? "default" : "ghost"}
                      size="sm"
                      onClick={() => toggleFavorite(previewPhoto)}
                    >
                      <Icon icon={IconStar} size="sm" decorative /> 重要
                    </Button>
                    <Button
                      variant="outline"
                      size="sm"
                      disabled={previewIndex >= filtered.length - 1}
                      onClick={() => setPreviewId(filtered[previewIndex + 1]?.id ?? null)}
                      aria-label="次の写真"
                    >
                      次へ <Icon icon={IconChevronRight} size="sm" decorative />
                    </Button>
                  </HStack>
                </div>

                {/* 黒板情報 */}
                <VStack gap={3}>
                  <MetadataList items={photoMetadata(previewPhoto)} wrap />
                  <Separator />
                  <VStack gap={1}>
                    <span className="text-xs font-medium text-muted-foreground">コメント</span>
                    <p className="text-sm">{previewPhoto.comment}</p>
                  </VStack>
                </VStack>
              </div>

              <DialogFooter>
                <Button
                  variant="outline"
                  onClick={() => {
                    setReportIds((prev) => Array.from(new Set([...prev, previewPhoto.id])));
                    showToast("この写真を台帳に追加しました", "success");
                  }}
                >
                  <Icon icon={IconFolderPlus} size="sm" decorative /> 台帳に追加
                </Button>
              </DialogFooter>
            </>
          )}
        </DialogContent>
      </Dialog>

      {/* ============ 写真アップロード ============ */}
      <Dialog open={uploadOpen} onOpenChange={setUploadOpen}>
        <DialogContent closeLabel="閉じる">
          <DialogHeader>
            <DialogTitle>写真を取り込む</DialogTitle>
            <DialogDescription>現場で撮影した写真を選択、またはドラッグ&ドロップで取り込みます。</DialogDescription>
          </DialogHeader>
          <FileUploader
            value={uploadFiles}
            onValueChange={setUploadFiles}
            accept={{ "image/*": [".jpg", ".jpeg", ".png", ".heic"] }}
            maxFiles={20}
            maxSize={20 * 1024 * 1024}
            labels={{
              browse: "写真を選択",
              drop: "ここに写真をドラッグ&ドロップ",
              maxSize: (mb) => `1ファイル最大 ${mb}MB`,
              removeFile: "削除",
            }}
          />
          <DialogFooter>
            <Button variant="outline" onClick={() => setUploadOpen(false)}>
              キャンセル
            </Button>
            <Button
              disabled={uploadFiles.length === 0}
              onClick={() => {
                showToast(`${uploadFiles.length} 枚を取り込みました`, "success");
                setUploadFiles([]);
                setUploadOpen(false);
              }}
            >
              取り込む（{uploadFiles.length}）
            </Button>
          </DialogFooter>
        </DialogContent>
      </Dialog>

      {/* ============ 台帳（アルバム）用の写真選択 ============ */}
      <MediaPickerDialog
        open={pickerOpen}
        onOpenChange={setPickerOpen}
        items={photos}
        multiSelect
        selectedIds={reportIds}
        labels={{
          title: "工事写真台帳にまとめる",
          description: "報告書アルバムに載せる写真を選びます。",
          searchPlaceholder: "写真を検索",
          confirm: (n) => `${n} 枚で台帳を作成`,
          cancel: "キャンセル",
          emptyTitle: "写真がありません",
        }}
        onConfirm={(items) => {
          setReportIds(items.map((i) => i.id));
          showToast(`${items.length} 枚で工事写真台帳を作成しました`, "success");
        }}
      />
    </div>
  );
}

/* ---------------- 是正 before/after セル ---------------- */
function BeforeAfterCell({
  label,
  tone,
  data,
}: {
  label: string;
  tone: "warning" | "success";
  data: { src: string; alt: string; date: string; note: string };
}) {
  return (
    <VStack gap={2}>
      <Badge variant={tone}>{label}</Badge>
      <ImagePreview
        src={data.src}
        alt={data.alt}
        aspectRatio="video"
        objectFit="cover"
        previewLabel="拡大"
        className="w-full rounded-md"
      />
      <VStack gap={1}>
        <HStack gap={1} align="center" className="text-xs text-muted-foreground">
          <Icon icon={IconCalendarEvent} size="xs" decorative />
          <span>{data.date}</span>
        </HStack>
        <p className="text-xs">{data.note}</p>
      </VStack>
    </VStack>
  );
}

